        flow: [{ from: "location", to: "geo", label: "fresh positions" }, { from: "geo", to: "dispatch", label: "candidates" }, { from: "dispatch", to: "trip", label: "fenced assignment" }, { from: "trip", to: "events", label: "state changes" }]
