      data: ["Menu(merchantId, menuVersion, effectiveAt) and MenuItem(itemId, price, availability, modifiers, taxClass).", "Order(orderId, customerId, merchantId, courierId, state, quoteId, version, totals, timestamps).", "OrderLine(snapshot of name/price/options), FulfillmentPlan, and immutable Payment/SettlementLedger entries."],
