      scope: "URL discovery, canonicalization, frontier scheduling, robots enforcement, fetching, content deduplication, and crawl storage are included; query serving and relevance ranking are excluded.",
      scale: { traffic: "4M fetches/s sustained", data: "100B known URLs; 40 PB fetched content/day", availability: "continuous pipeline; 99.9% high-priority freshness target" },
