      api: ["POST /internal/seeds accepts normalized seed sets and priority policy; it is administrative, not public crawl traffic.", "FrontierLease(hostKey, urls, leaseEpoch, expiresAt) assigns bounded work to a fetcher.", "FetchCompleted(urlFingerprint, fetchVersion, status, headers, contentRef, outlinksRef) is the durable pipeline event."],
      data: ["UrlState(fingerprint, canonicalUrl, hostKey, discoveredAt, nextFetchAt, priority, fetchVersion, status).", "HostState(hostKey, robotsVersion, crawlDelay, tokenBalance, nextEligibleAt, leaseEpoch, health).", "FetchArtifact(contentHash, bodyRef, headers, fetchedAt) and LinkBatch(sourceFingerprint, targetFingerprints)."],
      architecture: ["URL intake canonicalizes and deduplicates into a durable frontier partitioned by host; schedulers emit only eligible host batches.", "Sandboxed fetchers execute leased work, persist content by hash, and publish results that update recrawl state and discover links."],
      components: ["Canonicalizer normalizes schemes, hosts, ports, fragments, tracking parameters, redirects, and declared canonicals conservatively.", "Frontier combines priority queues with per-host token buckets and durable lease epochs.", "Fetcher pool handles DNS, robots, conditional GET, size/type limits, rendering tiers, and artifact checksums."],
      flows: ["Discovery: parse outlink, normalize, probabilistically prefilter, authoritative dedupe, assign host and initial priority.", "Fetch: scheduler grants host lease, fetcher rechecks robots, downloads within limits, stores artifact, acknowledges result.", "Recrawl: change frequency, importance, errors, and HTTP cache headers determine nextFetchAt with randomized backoff."],
      storage: ["Use an LSM-based distributed key-value store for URL/host state and object storage for immutable bodies/link batches.", "Kafka separates discovery, fetch results, parsing, and downstream indexing with replayable retention."],
      cache: ["Cache DNS and parsed robots rules by host with expiry, negative results, and policy versioning.", "Use Bloom filters only as a first-pass duplicate filter; authoritative state prevents false-positive URL loss."],
      partitioning: ["Partition frontier ownership by hostKey so one shard enforces each publisher's budget.", "Split giant hosts by approved path buckets only when a shared host-level limiter still caps aggregate traffic."],
      consistency: ["Host leases and token budgets need single-writer or conditional consistency; URL discovery and analytics may converge eventually.", "Robots deny changes enter a priority invalidation path and are rechecked immediately before fetch."],
      concurrency: ["Lease epochs fence recovered fetchers so expired workers cannot double-spend a host's crawl budget.", "URL fetchVersion makes duplicate completion safe and prevents an older fetch from overwriting newer state."],
      asynchronous: ["DNS resolution, fetching, parsing, rendering, link extraction, language detection, artifact compaction, and recrawl scoring are independent stages.", "Backpressure lowers long-tail discovery priority before it violates publisher budgets or durable queue limits."],
      failures: ["Worker loss returns leases after expiry; short leases improve recovery but increase scheduler write load.", "DNS/429/503 failures reduce host rate and honor Retry-After; permanent 4xx responses follow slower recrawl policy.", "Crawler traps are quarantined by URL-pattern budgets, depth limits, novelty checks, and per-host state growth alarms."],
      retry: ["Fetch attempts key by URL fingerprint and fetchVersion; redirects and Retry-After consume the same host policy budget.", "Artifact writes are content-addressed, and FetchCompleted consumers upsert only when the version is current."],
      security: ["Block loopback, link-local, metadata, and private network destinations after every DNS resolution and redirect.", "Sandbox parsers/renderers, cap bytes/time/redirects/decompression, rotate crawler identity responsibly, and audit legal exclusions."],
      observability: ["Measure fetch success, byte throughput, freshness by class, queue age, and useful-new-content yield.", "Track per-host request rate, robots decisions, 429s, lease duplication, DNS failures, and trap quarantine.", "Sample end-to-end URL histories from discovery through fetch and expose publisher-facing crawl diagnostics."],
      bottlenecks: ["A few enormous hosts and infinite calendar/filter spaces can dominate frontier state and bandwidth.", "JavaScript rendering is orders of magnitude costlier than HTTP fetch and must be a tightly budgeted second tier."],
      tradeoffs: ["Strict host ownership protects publishers but makes popular hosts hot shards; shared ownership requires coordinated rate limits.", "Aggressive recrawl improves freshness but reduces new coverage and increases publisher/network cost."],
      alternatives: ["Use breadth-first database queues for a small bounded domain corpus with low freshness demands.", "Delegate fetching to managed crawling services when compliance and unusual rendering are more important than unit economics."],
      mvp: ["A durable PostgreSQL frontier, robots-aware workers, object storage, normalized URLs, fixed per-host delay, and bounded retries.", "Restrict content types and depth, retain fetch metadata, and test SSRF protections before broad discovery."],
      intermediate: ["Partition by host, introduce Kafka stages, adaptive recrawl, Bloom prefilters, conditional GET, and sandboxed parsing.", "Add lease fencing, host health, rendering tiers, content hashes, and per-host anomaly budgets."],
      internetScale: ["Run global fetch cells with centrally assigned host ownership, multi-tier frontiers, and massive immutable artifact storage.", "Optimize scheduling by value per byte, isolate toxic domains, and continuously rebalance host shards without double crawling."],
      multiRegion: ["Assign each host to one active region so politeness remains global; fetch near publishers only after transferring fenced ownership.", "Replicate frontier checkpoints and artifacts, but do not run active-active schedulers for the same host budget."],
      cost: ["Bandwidth, object retention, DNS, and rendered pages dominate; conditional GET and content-addressed dedupe have high leverage.", "Delete or tier bodies after downstream extraction when audit/reprocessing policy allows, while retaining compact fetch metadata."],
      mistakes: ["Partitioning by URL instead of host and thereby violating aggregate publisher limits.", "Using Bloom-filter membership as authoritative or retrying every failure with the same backoff."],
      followups: ["How would you reassign a high-traffic host between regions without temporarily doubling crawl rate?", "How would you detect and stop an infinite faceted-navigation space?"],
      review: ["Verify canonicalization, robots timing, host budgets, lease fencing, SSRF controls, artifact checksums, and recrawl policy.", "Chaos-test worker loss, DNS rebinding, redirect loops, 429 storms, frontier hotspot moves, and parser bombs."],
