        flow: [{ from: "discover", to: "frontier", label: "canonical URLs" }, { from: "frontier", to: "fetch", label: "fenced leases" }, { from: "fetch", to: "objects", label: "content hash" }, { from: "fetch", to: "results", label: "FetchCompleted" }, { from: "results", to: "discover", label: "outlinks" }]
