        flow: [{ from: "agents", to: "collect", label: "sequenced batches" }, { from: "collect", to: "buffer", label: "durable append" }, { from: "buffer", to: "hot", label: "index" }, { from: "buffer", to: "archive", label: "compress" }, { from: "query", to: "hot", label: "bounded search" }]
