      data: ["Article(articleId, publisherId, canonicalUrl, contentHash, headline, bodyRef, locale, publishedAt, revision, rights, state).", "Story(storyId, topic, centroidRef, firstSeenAt, updatedAt, representativeArticleIds, policyState, version).", "FeedEntry(edition/user, storyId, rankScore, reason, generation) and Interaction(eventId, userId, storyId, type, occurredAt)."],
      architecture: ["Publisher connectors feed a versioned enrichment pipeline that extracts, deduplicates, classifies, embeds, and updates story clusters/search indexes.", "Feed service merges editorial, trending, followed-topic, local, and personalized candidates, then applies policy/diversity constraints and hydrates story cards."],
      components: ["Ingestion service honors publisher cadence/rights and preserves revision lineage rather than treating every URL as a new article.", "Clustering service combines canonical URL, content hashes, entity/time similarity, and embeddings with merge/split history.", "Feed ranker balances relevance, recency, authority, viewpoint/source diversity, fatigue, and explicit editorial rules."],
      flows: ["Ingest: receive update, fetch/validate, fingerprint, extract, classify, cluster, index, publish projection change.", "Read: choose edition, retrieve candidate pools, filter rights/policy, rank with diversity constraints, hydrate, cursor page.", "Correction: append revision, update representative card, invalidate affected clusters/feed heads, retain visible correction lineage."],
