      api: ["POST /v1/ad-decisions accepts placement, page/app context, coarse audience signals, consent, requestId, and deadline.", "Decision response carries creative URL, render token, campaign/decision IDs, expiry, and signed measurement endpoints.", "Opportunity, Impression, Click, Conversion, SpendAdjusted, and CampaignExhausted events share lineage identifiers."],
      data: ["Campaign(id, advertiserId, objective, targetingRef, bid, budget, schedule, pacing, state, version).", "Creative(id, campaignId, assetRef, format, approvals, landingDomain, version) and Placement policy.", "BudgetLease(campaignId, servingCell, amount, spent, epoch, expiresAt), FrequencyState(subjectHash, campaignId, window, count), and AdEvent."],
      architecture: ["Control-plane changes compile approved campaigns into immutable, regionally distributed serving snapshots and retrieval indexes.", "Stateless decision servers retrieve candidates, apply consent/policy/caps, score under deadline, consume local budget lease, and emit events asynchronously."],
      components: ["Campaign compiler validates assets/policies and creates deterministic targeting bytecode plus versioned indexes.", "Candidate service prunes by placement, geography, schedule, topic, and coarse audience before the ranker/auction.", "Budget/pacing service allocates expiring cell leases from campaign budgets and reconciles event-derived spend."],
      flows: ["Publish: validate campaign/creative, approve, compile snapshot, distribute, canary, activate at effective version.", "Serve: validate context/consent, fetch candidates, apply hard filters/caps, score/auction, spend lease, sign response, emit opportunity.", "Measure: client/publisher sends signed impression/click; pipeline deduplicates, detects invalid traffic, attributes, bills, and updates pacing."],
      storage: ["Use relational storage for campaign/billing control data and object storage/CDN for immutable creatives and snapshots.", "Use Redis/key-value stores for leased budgets/caps, Kafka for events, and ClickHouse/object storage for reporting and reconciliation."],
      cache: ["Decision nodes memory-map immutable campaign snapshots and cache candidate lists by placement/coarse context/version.", "Frequency state uses bounded TTL and privacy-safe subject hashes; creative assets are long-lived CDN objects by digest."],
      partitioning: ["Partition serving by region/placement and campaign retrieval index; replicate hot broad campaigns across every cell.", "Partition events by decisionId or campaignId according to ordering need; allocate spend leases to avoid a single campaign counter hotspot."],
      consistency: ["Campaign approval/version and billing ledger are authoritative; serving snapshots and reports converge by version/event time.", "Budgets and frequency caps are bounded-approximate through leases/local state; prohibited-policy changes use emergency deny propagation."],
      concurrency: ["Serving cells atomically consume leased spend and stop before lease exhaustion; epochs fence expired allocations.", "Event dedupe keys combine decision/event type/provider occurrence so retries cannot bill twice."],
      asynchronous: ["Snapshot compilation, event attribution, invalid-traffic detection, spend reconciliation, reporting, and model training are asynchronous.", "Decision serving has no synchronous warehouse or billing dependency; events spool locally if Kafka is briefly unavailable."],
      failures: ["Ranker or feature failure uses a prevalidated contextual fallback; policy filters remain mandatory.", "Budget service outage spends only unexpired local leases, then stops affected campaigns rather than allowing unbounded overspend.", "Event lag affects pacing/report freshness; reconciliation corrects spend and billing with adjustment entries."],
      retry: ["Decision requestId stabilizes auction outcome within a short window; a retry returns the prior decision when available.", "Measurement endpoints accept stable occurrence IDs, deduplicate at ingest and billing, and reject invalid signatures/expiry."],
      security: ["Minimize personal data, enforce consent strings, prohibit sensitive targeting, rotate subject hashes, and separate contextual from behavioral stores.", "Scan creatives/landing domains, sign measurement tokens, prevent click fraud/replay, protect campaign admin, and audit policy overrides."],
      observability: ["Measure decision p50/p99, no-fill, candidate counts, policy exclusions, model fallback, and timeout by placement/cell.", "Track budget lease utilization/overshoot, pacing error, frequency-cap error, event lag, invalid traffic, and billing reconciliation deltas.", "Continuously replay golden contexts against snapshot versions for policy and scoring regression."],
      bottlenecks: ["Broad high-budget campaigns become retrieval and budget hot keys; unpruned candidates break the latency deadline.", "Large launches and breaking news produce request/event bursts plus advertiser reporting storms."],
      tradeoffs: ["More precise global budgets/caps reduce overshoot but add serving latency and availability dependency.", "Behavioral personalization can improve yield while increasing privacy, policy, feature freshness, and model-governance costs."],
